changeSet.sql:
INSERT INTO permissions (name, description)
VALUES ('plugin_deviceremote_access', 'Remote control of devices');
INSERT INTO userRolePermissions (roleId, permissionId)
SELECT id, currval('permissions_id_seq')
FROM userroles;

CREATE TABLE plugin_deviceremote_settings (
    id serial NOT NULL CONSTRAINT plugin_deviceremote_settings_pr_key PRIMARY KEY,
    customerId INT NOT NULL UNIQUE REFERENCES customers (id) ON DELETE CASCADE,
    serverUrl VARCHAR(500) NOT NULL DEFAULT '',
    serverSecret VARCHAR(200) NOT NULL DEFAULT ''
);
